import { createGlobalStyle } from 'styled-components';

export const GlobalStyle = createGlobalStyle`
  html {
    box-sizing: border-box;
    font-size: 16px; 
  }
  
  *,
  *:before,
  *:after {
    box-sizing: inherit;
  }
  body,
  h1,
  h2,
  h3,
  h4,
  h5,
  h6,
  p,
  ol,
  ul {
    margin: 0;
    padding: 0;
    font-weight: normal;
  }
  h1,
  h2,
  h3,
  h4,
  h5,
  h6 {
    font-weight: bold;
  }

  ol,
  ul {
    list-style: none;
  }

  img {
    max-width: 100%;
    height: auto;
  }

  a {
    color: inherit;
    text-decoration: none;
  }

  // Customize scrollbar
  &::-webkit-scrollbar {
    width: 0.55rem;
  }

  &::-webkit-scrollbar-track {
    background: #ddddf0
  }

  &::-webkit-scrollbar-thumb {
    background: #33023d;
  }

  html {
    scroll-behavior: smooth;
  }
`;
